SELECT COUNT(DISTINCT user_id)
FROM activity_logs
WHERE steps > 0;

SELECT COUNT(DISTINCT ag.group_admin_id) 
FROM activity_groups ag
WHERE ag.group_type = 'private';

SELECT plan_type, COUNT(plan_id) AS plan_count
FROM fitness_plans
GROUP BY plan_type;

SELECT DISTINCT activity_name
FROM activity_types
ORDER BY difficulty_level ASC;
